content.content:
[
  {
    "tool": "search_files_by_filename",
    "args": {
      "filename": "recipe-collection.docx"
    }
  },
  {
    "tool": "query_llm",
    "args": {
      "prompt": "Extract the file_id of the first file from the following list of files: <tool_result_0/>. Return only the file_id as plain text."
    }
  },
  {
    "tool": "get_file_by_id",
    "args": {
      "file_id": "<query_llm_0/>"
    }
  },
  {
    "tool": "query_llm",
    "args": {
      "prompt": "From the content of the file provided in <tool_result_1/>, extract the list of ingredients for the recipe titled 'Chocolate Chip Cookies'. Return the ingredients as a plain text list, each ingredient on a separate line."
    }
  },
  {
    "tool": "search_files_by_filename",
    "args": {
      "filename": "grocery"
    }
  },
  {
    "tool": "query_llm",
    "args": {
      "prompt": "Extract the file_id of the first file from the following list of files: <tool_result_2/>. Return only the file_id as plain text."
    }
  },
  {
    "tool": "append_to_file",
    "args": {
      "file_id": "<query_llm_2/>",
      "content": "\n<query_llm_1/>"
    }
  }
]
